<?php
namespace App\Models;
use App\Models\Concerns\BelongsToTenant; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\{BelongsTo,HasMany};
class Guard extends Model { use BelongsToTenant; protected $fillable=['tenant_id','user_id','employee_number','first_name','last_name','phone','email','status','hourly_rate','license_number','license_expires_at','emergency_contact_name','emergency_contact_phone']; protected $appends=['full_name']; protected function casts(): array { return ['license_expires_at'=>'date']; } public function user(): BelongsTo { return $this->belongsTo(User::class); } public function getFullNameAttribute(): string { return trim($this->first_name.' '.$this->last_name); } public function documents(): HasMany { return $this->hasMany(GuardDocument::class); } public function certifications(): HasMany { return $this->hasMany(GuardCertification::class); } public function assignments(): HasMany { return $this->hasMany(ShiftAssignment::class); } }
